Contents of https://github.com/dotnet/runtime/issues/126679:
### Description

A piece of C# code used for JSON token serialization is performing noticeably worse on ARM64 than X64 with .NET 10. This is observed on Azure VM SKUs D16ps\_v6 (ARM64/Cobalt 100) vs. D16as\_v6 (X64/AMD 9V74).

BenchmarkDotNet repro code snippet (courtesy of Egor B and Max B):

```
using System.Text;
using System.Text.Json;
using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Running;

BenchmarkSwitcher.FromAssembly(typeof(Benchmarks).Assembly).Run(args);

[MemoryDiagnoser]
public class Benchmarks
{
    // ── TokenSerialization fields ────────────────────────────────────────────
    private List<object> _tokenObjects;
    [ThreadStatic] static Utf8JsonWriter t_writer;
    [ThreadStatic] static MemoryStream t_stream;

    public void Setup()
    {
        // TokenSerialization
        _tokenObjects = new List<object>(200);
        for (int i = 0; i < 200; i++)
        {
            if (i % 3 == 0)
                _tokenObjects.Add(GenerateRecordJson(1));
            else
                _tokenObjects.Add(new Dictionary<string, object>
                {
                    ["seq"] = i,
                    ["label"] = $"item_{i}",
                    ["blob"] = new byte[100]
                });
        }
    }

    private static string GenerateRecordJson(int targetSizeKb = 150)
    {
        var sb = new StringBuilder(targetSizeKb * 1024 + 512);
        sb.Append("{");
        sb.Append("\"TypeName\":\"product\",");
        sb.Append("\"CategoryCode\":1,");
        sb.Append("\"Label\":\"Product\",");
        sb.Append("\"IsAction\":false,");
        sb.Append("\"IsActionMember\":false,");
        sb.Append("\"IsTrackingEnabled\":true,");
        sb.Append("\"IsAvailableLocal\":true,");
        sb.Append("\"IsChildRecord\":false,");
        sb.Append("\"IsLinksEnabled\":true,");
        sb.Append("\"IsCustomRecord\":false,");
        sb.Append("\"PrimaryKeyField\":\"productid\",");
        sb.Append("\"PrimaryLabelField\":\"title\",");
        sb.Append("\"Fields\":[");
        int targetBytes = targetSizeKb * 1024;
        int fieldIndex = 0;
        bool firstField = true;
        while (sb.Length < targetBytes - 512)
        {
            if (!firstField) sb.Append(",");
            firstField = false;
            sb.Append("{");
            sb.Append($"\"TypeName\":\"field_{fieldIndex}\",");
            sb.Append($"\"InternalName\":\"Field_{fieldIndex}\",");
            sb.Append($"\"FieldType\":\"String\",");
            sb.Append($"\"Label\":\"Field {fieldIndex}\",");
            sb.Append($"\"MaxSize\":100,");
            sb.Append($"\"IsReadable\":true,");
            sb.Append($"\"IsCreatable\":true,");
            sb.Append($"\"IsUpdatable\":true,");
            sb.Append($"\"IsTrackingEnabled\":false,");
            sb.Append($"\"IsPrimaryKey\":false,");
            sb.Append($"\"IsVirtual\":false,");
            sb.Append($"\"Requirement\":\"None\"");
            sb.Append("}");
            fieldIndex++;
        }
        sb.Append("]");
        sb.Append("}");
        return sb.ToString();
    }

    [Benchmark]
    public void TokenSerialization()
    {
        var stream = t_stream ??= new MemoryStream(64 * 1024);
        stream.Position = 0;
        stream.SetLength(0);
        var writer = t_writer;
        if (writer == null)
        {
            writer = new Utf8JsonWriter(stream, new JsonWriterOptions { SkipValidation = true });
            t_writer = writer;
        }
        else
            writer.Reset(stream);
        writer.WriteStartObject();
        writer.WriteStartArray("Catalog");
        foreach (var token in _tokenObjects)
        {
            if (token is string strToken)
            {
                if (!string.IsNullOrEmpty(strToken))
                    writer.WriteRawValue(strToken);
            }
            else if (token is Dictionary<string, object> dictToken)
            {
                writer.WriteStartObject();
                foreach (var kvp in dictToken)
                {
                    writer.WritePropertyName(kvp.Key);
                    JsonSerializer.Serialize(writer, kvp.Value);
                }
                writer.WriteEndObject();
            }
        }
        writer.WriteEndArray();
        writer.WriteEndObject();
        writer.Flush();
        if (stream.Length == 0) throw new Exception("unreachable");
    }
}
```

Add this code to Benchmark.cs file in a C# project with target frameworks for net10.0 and net481 and a package reference to the latest BenchmarkDotNet. Build and run on machines with .NET SDK 10.x:

*   ARM64: `dotnet run -c Release --framework net10.0 --runtime win-arm64 -- --filter *TokenSerialization* --runtimes net481 net10.0`
*   X64: `dotnet run -c Release --framework net10.0 --runtime win-x64 -- --filter *TokenSerialization* --runtimes net481 net10.0`

### Configuration

*   .NET 10.0.5.
*   Windows Server 2025 for X64 and ARM64 (Includes .NET Framework 4.8.1).
*   Azure D16as\_v6 VM SKU size for X64.
*   Azure D16ps\_v6 VM SKU size for ARM64.

### Regression?

Yes, on .NET Framework 4.8.1 performance on X64 and ARM64 is about the same. On .NET 10, ARM64 is noticeably slower.

### Data

```
VM SKU   | Arch  | Runtime    | Mean μs | Error μs | StdDev μs | GCM Mean μs | GCM P80 μs |
---------|-------|------------|--------:|---------:|----------:|------------:|-----------:|
D16as_v6 | X64   | .NET 4.8.1 |  288.90 |    0.208 |     0.184 |      295.50 |     296.50 |
D16as_v6 | X64   | .NET 10.0  |   67.96 |    0.054 |     0.048 |       96.50 |      70.20 |
D16ps_v6 | ARM64 | .NET 4.8.1 |  291.31 |    0.700 |     0.655 |      298.40 |     300.50 |
D16ps_v6 | ARM64 | .NET 10.0  |   97.13 |    0.040 |     0.038 |      140.80 |     173.50 |
```

### Analysis

With .NET Framework 4.8.1 the Mean is about the same on X64 and ARM64.  
With .NET 10, the Mean is about 43% higher on ARM64 than on X64.  
Expecting that performance would still be on par with .NET 10 when it was with .NET Framework 4.8.1.

